INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 72032, "vo_asb_0726", "", 72, "", "vo_asb", 21, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (10, 0, 1, 72033, "そりゃそうですよね……\nいきなり前のめり過ぎ太郎でした……", 1, 72, 0, 1, 11, 0);
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 72034, "", "", 72, "", 0, 91, "");
