INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (10, 0, 1, 82013, "その頃わたくしは、\nスカウトをお受けしておりました。\nミサト様いわく、わたくしには保育士の\n『天賦の才』があるそうで。", 1, 82, 0, 1, 11, 0);
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 82014, "", "", 82, "", 0, 91, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (1, "", "", 82015, "sad_talk_surprise", "", 82, 0.2, 1, 3, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 82016, "vo_asb_0822", "", 82, "", "vo_asb", 21, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (10, 0, 1, 82017, "小さいお子様はともかく、動物さんに\n好かれる自覚はありますし……\n冒険者という仕事に不向きなことも、\n自認していますけれど……", 1, 82, 0, 1, 11, 0);
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 82018, "", "", 82, "", 0, 91, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (1, "", "", 82019, "guts2_talk_Ex1", "", 82, 0.2, 1, 3, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 82020, "vo_asb_0823", "", 82, "", "vo_asb", 21, "");
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (10, 0, 1, 82021, "それでも……適性など踏み越えて、\n己の道を突き進むのが冒険者です。\n一度決めたことを、\n曲げるわけには参りません……！", 1, 82, 0, 1, 11, 0);
INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (0, "", 0, 82022, "", "", 82, "", 0, 91, "");
