INSERT INTO `v1_ef70c446eed91c96cd6836ca2b7f4d6875cb3ffbbbd02e0ba7ea8a765f55503d` VALUES (10, 0, 1, 142024, "……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 1, 142, 0, 1, 11, 0);
